import{_ as e,c as t,o as a,f as i}from"./chunks/framework.BOAZPCR7.js";const g=JSON.parse('{"title":"Strain-specific differences in the response to egg-derived versus recombinant protein influenza vaccines","description":"","frontmatter":{"layout":"paper","title":"Strain-specific differences in the response to egg-derived versus recombinant protein influenza vaccines","date":"2026-02-23","authors":["Andrea N Loes","Rosario AL Tarabi","Shuk H Li","Reilly K Atkinson","John Huddleston","Caroline Kikawa","Tachianna Griffiths","Elizabeth M Drapeau","Sook-San Wong","Samuel MS Cheng","Nancy HL Leung","Sarah Cobey","Benjamin J Cowling","Trevor Bedford","Scott E Hensley","Jesse D Bloom"],"journal":"bioRxiv","doi":"10.64898/2026.02.23.707528","link":"https://doi.org/10.64898/2026.02.23.707528","image":"/assets/papers/2026_loes.jpg","selected":false,"keywords":["Influenza","Immunity","Sequencing-based neutralization"],"head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/papers/2026_loes.html"}]]},"headers":[],"relativePath":"papers/2026_loes.md","filePath":"papers/2026_loes.md"}'),n={name:"papers/2026_loes.md"},r=i('<h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The 2023/2024 influenza vaccine included an updated H1N1 component designed to better match a new clade of H1N1 that had multiple mutations in antigenic epitopes of hemagglutinin. Despite this update, the vaccine trended towards being less effective against the vaccine-matched H1N1 clade than the parental H1N1 clade lacking the new antigenic mutations. Here we measure neutralization titers of serum antibodies from individuals who had received either a recombinant protein or an egg-derived vaccine against a set of viruses with hemagglutinins from 58 H1N1 strains representative of the diversity during the 2023/2024 season. We find that egg-derived vaccine recipients, but not recombinant protein vaccine recipients, had a relatively lower boost in neutralizing titers to the new clade that the updated vaccine was designed to target. We suggest that the difference in the extent that the egg-derived versus recombinant protein vaccines boost neutralizing titers to the new H1N1 clade is because the seed strain for the egg-derived vaccine strain had acquired a reversion of a key antigenic mutation (K142R) present in that clade. Our results show how egg-derived versus recombinant protein vaccines can elicit different relative titer boosts against different subsets of viral strains, a phenomenon that could impact vaccine effectiveness.</p><h2 id="data" tabindex="-1">Data <a class="header-anchor" href="#data" aria-label="Permalink to &quot;Data&quot;">​</a></h2><p>The neutralization data described in this paper is available at <a href="https://github.com/jbloomlab/flu_seqneut_pdmH1N1_2023-2024_VaccinatedCohorts" target="_blank" rel="noreferrer">https://github.com/jbloomlab/flu_seqneut_pdmH1N1_2023-2024_VaccinatedCohorts</a>.</p>',4),s=[r];function o(c,d,l,h,p,u){return a(),t("div",null,s)}const m=e(n,[["render",o]]);export{g as __pageData,m as default};
